public class BisectionSolver extends UnivariateRealSolverImpl {
    @Override
    public double solve(final UnivariateRealFunction f, double min, double max){
        if (!Double.isNaN(max - min)) {
            // Preconditions in this implementation of the bisection method don't prevent it from functioning with NaN or Infinity
            if ((f.value(min) > 0 && f.value(max) < 0) || (f.value(min) < 0 && f.value(max) > 0)){
                return super.solve(f, min, max);
            } else if (f.value(min) == 0){
                return min;
            } else if (f.value(max) == 0){
                return max;
            } else {

                throw new MaxCountExceededException();
            }
        } else{

            throw new NoBracketFoundException();
        }
    }

    public double solve(final UnivariateRealFunction f, double min, double max, double initialGuess)
            throws NullPointerException {

        if (f == null){
          throw new NullPointerException("The input function cannot be null");
        }
        return solve(f, min, max);
    }

    static class NoBracketFoundException extends RuntimeException{}
    static class MaxCountExceededException extends RuntimeException{}
    private static final long serialVersionUID = -6724837645898861087L;
}

